const parts = msg.topic.split('/');
const deviceId = parts[4] || '?';
const field = parts[5] || '?';
msg.payload = { deviceId, field, value: msg.payload, t: new Date().toISOString() };
return msg;

msg.headers = {
  'Authorization': 'Bearer hi-relay-token-test-2024',
  'Content-Type': 'application/json',
  'X-Request-Id': 'nr-test-' + Date.now()
};
msg.method = 'POST';
msg.url = 'http://alice-adapter:3000/internal/p4/state-change';
return msg;

// topic: demo/v1/server/devices/{device_id}/{field}
const parts = msg.topic.split('/');
const deviceId = parts[4];
const field    = parts[5];
if (!deviceId || !field) return null;

const cache = flow.get('mqttState') || {};
if (!cache[deviceId]) cache[deviceId] = { _updated: new Date().toISOString() };

if (field === 'State') {
  cache[deviceId].on = (msg.payload === 'True' || msg.payload === 'true' || msg.payload === true);
} else if (field === 'TemperatureValue') {
  const t = parseFloat(msg.payload);
  if (!isNaN(t)) cache[deviceId].temperature = t;
} else if (field === 'HumidityValue') {
  const h = parseFloat(msg.payload);
  if (!isNaN(h)) cache[deviceId].humidity = h;
} else {
  cache[deviceId][field] = msg.payload;
}
cache[deviceId]._updated = new Date().toISOString();
flow.set('mqttState', cache);
return null;

const auth = msg.req.headers['authorization'] || '';
if (auth !== 'Bearer hi-relay-token-test-2024') {
  msg.statusCode = 401;
  msg.payload = { error: 'Unauthorized' };
  return msg;
}
const houseId = msg.req.params.house_id;
msg.payload = {
  house_id: houseId,
  version: 1,
  fetched_at: new Date().toISOString(),
  devices: [
    {
      logical_device_id: 'switch_903858',
      kind: 'relay',
      semantics: 'light',
      name: 'Офисный свет',
      room: 'Офис',
      online: true,
      board_id: 'real-controller-01'
    },
    {
      logical_device_id: 'ds18b20_155881',
      kind: 'ds18b20',
      name: 'Температура в офисе',
      room: 'Офис',
      online: true,
      board_id: 'real-controller-01'
    },
    {
      logical_device_id: 'ds18b20_959340',
      kind: 'ds18b20',
      name: 'Температура (доп. датчик)',
      room: 'Офис',
      online: true,
      board_id: 'real-controller-01'
    },
    {
      logical_device_id: 'shtanddht_509766',
      kind: 'dht_temp',
      name: 'Климат в офисе',
      room: 'Офис',
      online: true,
      board_id: 'real-controller-01'
    }
  ]
};
return msg;

const auth = msg.req.headers['authorization'] || '';
if (auth !== 'Bearer hi-relay-token-test-2024') {
  msg.statusCode = 401;
  msg.payload = { error: 'Unauthorized' };
  return msg;
}
const houseId = msg.req.params.house_id;
const { device_ids = [] } = msg.payload || {};
const mqttState = flow.get('mqttState') || {};
const now = new Date().toISOString();

const KIND = {
  'switch_903858':   'relay',
  'ds18b20_155881':  'ds18b20',
  'ds18b20_959340':  'ds18b20',
  'shtanddht_509766': 'dht_temp'
};

msg.payload = {
  house_id: houseId,
  fetched_at: now,
  devices: device_ids.map(id => {
    const s = mqttState[id];
    const kind = KIND[id] || 'relay';
    const online = !!s;
    const updated = s ? s._updated : now;
    let properties = [];

    if (kind === 'relay') {
      const on = s ? (s.on === true) : false;
      properties = [{ key: 'on', value: on, updated_at: updated }];
    } else if (kind === 'ds18b20') {
      const temp = s && s.temperature !== undefined ? s.temperature : null;
      if (temp !== null) {
        properties = [{ key: 'temperature', value: temp, updated_at: updated }];
      }
    } else if (kind === 'dht_temp') {
      if (s && s.temperature !== undefined) {
        properties.push({ key: 'temperature', value: s.temperature, updated_at: updated });
      }
      if (s && s.humidity !== undefined) {
        properties.push({ key: 'humidity', value: s.humidity, updated_at: updated });
      }
    }

    return { logical_device_id: id, online, properties };
  })
};
return msg;

const auth = msg.req.headers['authorization'] || '';
if (auth !== 'Bearer hi-relay-token-test-2024') {
  msg.statusCode = 401;
  msg.payload = { error: 'Unauthorized' };
  return [msg, null];
}
const intent = msg.payload || {};
const houseId = msg.req.params.house_id;
const deviceId = intent.device_id;
const property = intent.property;
const value = intent.value;

// Debounce: drop duplicate commands within 150ms per device
const debounceKey = 'debounce_' + deviceId;
const lastTs = context.get(debounceKey) || 0;
const now = Date.now();
if (now - lastTs < 150) {
  // Too soon — drop silently, return success response without publishing
  node.warn('Debounced action for ' + deviceId + ' (' + (now - lastTs) + 'ms)');
  msg.payload = {
    status: 'ok',
    request_id: intent.request_id || '',
    house_id: houseId,
    device_id: deviceId
  };
  return [msg, null];
}
context.set(debounceKey, now);

// Convert boolean → controller string format
let mqttPayload;
if (property === 'on') {
  mqttPayload = value ? 'True' : 'False';
} else {
  mqttPayload = String(value);
}

const mqttMsg = {
  topic: 'demo/v1/client/devices/' + deviceId + '/State',
  payload: mqttPayload,
  qos: 1,
  retain: false
};

node.warn('Action → MQTT: ' + mqttMsg.topic + ' = ' + mqttPayload);

msg.payload = {
  status: 'ok',
  request_id: intent.request_id || '',
  house_id: houseId,
  device_id: deviceId
};
return [msg, mqttMsg];
